-- 1. Создание таблицы
CREATE TABLE financial_expenditures_profit (
    industry TEXT, -- Отрасль / вид деятельности
    col1 NUMERIC(20, 0),   -- Количество организаций представивших отчет, единиц
    col2 NUMERIC(20, 0),   -- Общий объем израсходованных денежных средств по всем видам деятельности, тыс рублей
    col3 NUMERIC(20, 0),   -- Расходы по финансированию долгосрочных инвестиций
    col4 NUMERIC(20, 0),   -- Долгосрочные инвестиции по обычным видам деятельности
    col5 NUMERIC(20, 0),   -- Расходы на финансирование затрат по капитальным вложениям
    col6 NUMERIC(20, 0),   -- Расходы на создание и приобретение программного обеспечения
    col7 NUMERIC(20, 0),   -- Расходы на научно-исследовательские и опытно-конструкторские работы
    col8 NUMERIC(20, 0),   -- Расходы обслуживающих производств и хозяйств, состоящих на балансе
    col9 NUMERIC(20, 0),   -- Текущие расходы на содержание объектов санаторно-курортных учреждений
    col10 NUMERIC(20, 0),  -- Текущие расходы на содержание детских садов и яслей
    col11 NUMERIC(20, 0),  -- Текущие расходы на содержание пансионатов, домов отдыха, детских лагерей
    col12 NUMERIC(20, 0),  -- Текущие расходы на содержание объектов физкультурно-оздоровительной деятельности
    col13 NUMERIC(20, 0),  -- Текущие расходы на содержание объектов образования
    col14 NUMERIC(20, 0),  -- Текущие расходы на содержание учреждений клубного типа
    col15 NUMERIC(20, 0),  -- Расходы по предоставлению услуг лечебных санаторно-курортных учреждений
    col16 NUMERIC(20, 0),  -- Оплата сторонних организаций по предоставлению услуг лечебных и санаторно-курортных учреждений
    col17 NUMERIC(20, 0),  -- Расходы по предоставлению услуг пансионатов, домов отдыха, детских лагерей
    col18 NUMERIC(20, 0),  -- Оплата сторонних организаций по предоставлению услуг пансионатов, домов отдыха, детских лагерей
    col19 NUMERIC(20, 0),  -- Расходы по предоставлению услуг физкультурно-оздоровительной деятельности
    col20 NUMERIC(20, 0),  -- Оплата сторонних организаций по предоставлению услуг физкультурно-оздоровительной деятельности
    col21 NUMERIC(20, 0),  -- Расходы по предоставлению услуг образования
    col22 NUMERIC(20, 0),  -- Оплата сторонних организаций по предоставлению услуг образования
    col23 NUMERIC(20, 0),  -- Расходы по предоставлению услуг учреждений клубного типа
    col24 NUMERIC(20, 0),  -- Оплата сторонних организаций по предоставлению услуг учреждениям клубного типа
    col25 NUMERIC(20, 0),  -- Выплаты социального характера работникам
    col26 NUMERIC(20, 0),  -- Надбавки к пенсиям, единовременные пособия уходящим на пенсию
    col27 NUMERIC(20, 0),  -- На благотворительные цели
    col28 NUMERIC(20, 0),  -- Перечислено обособленным структурным подразделениям, имеющим отдельный баланс и расчетный счет
    col29 NUMERIC(20, 0),  -- Представительские расходы
    col30 NUMERIC(20, 0),  -- Оплата услуг банков и других финансово-кредитных учреждений
    col31 NUMERIC(20, 0),  -- Оплата услуг рекламных агентств и аудиторских организаций
    col32 NUMERIC(20, 0)   -- Отчисления в отраслевые и межотраслевые внебюджетные фонды научно-исследовательских и опытно-конструкторских работ
);

-- 2. Вставка данных
